/* ROBUST VERSION v1.2.2 - handles all Telegram input paths */
const input = $input.first()?.json;

const bodyLayer = input?.body || input || {};
const message = bodyLayer.message || bodyLayer.channel_post || bodyLayer;

const chat_id = message.chat?.id || bodyLayer.chat_id || input?.chat_id;
const text = message.text || bodyLayer.text || input?.text;

let isValid = true;
let error_message = null;

if (!chat_id || !text) {
  isValid = false;
  error_message = 'Payload missing required chat_id or text fields.';
}

const username = message.from?.first_name || message.chat?.first_name || bodyLayer.username || 'Unknown';

// SEC_02: Sanitize
const safeText = String(text || '').replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 500);
const safeUsername = String(username || '').replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 100);

return [{
  json: {
    isValid,
    error_message,
    chat_id,
    text: safeText,
    username: safeUsername
  }
}];

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      chat_id: $json.chat_id,
      text: $json.text,
      username: $json.username,
      type: 'text'
    },
    _meta: { source: 'NN_02_Message_Parser', timestamp: new Date().toISOString(), version: '1.2.2' }
  }
}];

return [{
  json: {
    success: false,
    error_code: 'VALIDATION_ERROR',
    error_message: $json.error_message,
    data: null,
    _meta: { source: 'NN_02_Message_Parser', timestamp: new Date().toISOString(), version: '1.2.2' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT (O02)
// Retorna esquema unificado para todos los workflows

const result = $input.first()?.json || {};

return [{
  json: {
    success: result.success !== false,
    error_code: result.success === false ? (result.error_code || 'UNKNOWN_ERROR') : null,
    error_message: result.success === false ? (result.error_message || 'An error occurred') : null,
    data: result.data || null,
    _meta: {
      source: 'NN_02_MESSAGE_PARSER',
      workflow_id: 'NN_02_MESSAGE_PARSER',
      timestamp: new Date().toISOString(),
      version: '4.3.1'
    }
  }
}];
